"""RunContext — 실행 상태."""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any

from mantis.models.node import NodeInfo, EdgeInfo
from mantis.runtime.port_store import PortStore
from mantis.runtime.stream_manager import StreamManager
from mantis.runtime.route_resolver import RouteResolver


@dataclass
class RunContext:
    """한 번의 execute() 호출에 대한 실행 상태."""

    nodes: dict[str, NodeInfo]
    edges: list[EdgeInfo]
    execution_order: list[str]
    excluded: set[str] = field(default_factory=set)
    port_store: PortStore | None = None
    stream_manager: StreamManager | None = None
    route_resolver: RouteResolver | None = None
    hooks: list[Any] = field(default_factory=list)
    input_data: dict[str, Any] = field(default_factory=dict)
    pending_events: list[dict] = field(default_factory=list)
    endnode_ids: list[str] = field(default_factory=list)

    # ─── Providers (기존 mantis 모듈 연결) ───
    tool_registry: Any | None = None     # ToolRegistry
    search: Any | None = None            # GraphToolManager / SearchProvider
    sandbox: Any | None = None           # SandboxProvider (DockerSandbox)
    workflows: Any | None = None         # WorkflowStore
    state: Any | None = None             # StateStore
    model: Any | None = None             # LLMProvider (에이전트 노드용)

    def emit(self, event: dict) -> None:
        self.pending_events.append(event)

    def flush_events(self) -> list[dict]:
        events = list(self.pending_events)
        self.pending_events.clear()
        return events
